-- Player-photo export — name-keyed, idempotent.
-- Generated 2026-05-29 from foosball-mariadb.
-- Source: tbl_player_photo JOIN tbl_players (39 photos).
--
-- Usage on target machine:
--   mysql -u<user> -p<pwd> <db> < photos-export-2026-05-29.sql
--
-- Assumes the schema is already in place (Flyway V1+V5 applied).
-- Players whose name isn't in tbl_players on the target are skipped
-- (the INSERT ... SELECT yields zero rows). Existing photos are
-- overwritten via ON DUPLICATE KEY UPDATE.

START TRANSACTION;

INSERT INTO tbl_player_photo (player_id, photo, photo_mime)
  SELECT id, , 'image/jpeg'
    FROM tbl_players WHERE name = 'Allan'
  ON DUPLICATE KEY UPDATE photo = VALUES(photo), photo_mime = VALUES(photo_mime);
